// // This module converts a 4-bit binary input representing the temperature in degrees Celsius (0-15) into a 3-bit binary value indicating a warning level. The output is 3'b000 for temperatures below 5°C, 3'b001 for temperatures between 5°C and 10°C, 3'b010 for temperatures between 10°C and 15°C, and 3'b011 for temperatures above 15°C.
module temperature_sensor_controller(
    input [3:0] temperature,
    output reg [2:0] warning_level
);
    always @(*) begin
        if (temperature < 5) 
            warning_level = 3'b000; // Below 5°C
        else if (temperature < 10) 
            warning_level = 3'b001; // 5°C to 9°C
        else if (temperature < 15) 
            warning_level = 3'b010; // 10°C to 14°C
        else 
            warning_level = 3'b011; // 15°C and above
    end
endmodule
